// Verifies Calendly's webhook signature.
// Header format: 'Calendly-Webhook-Signature: t=<timestamp>,v1=<hex-hmac>'
// Signed payload is the string '<timestamp>.<rawBody>', HMAC-SHA256'd with
// the signing key from Calendly's webhook subscription settings.
//
// NOTE ON n8n VERSIONS: this reads the raw body from the binary property
// n8n's Webhook node produces when 'Raw Body' is enabled. The exact
// property path (here: $binary.data) has shifted across n8n releases —
// if this throws, open the Webhook node's output in the n8n UI, find
// where the raw body actually landed, and adjust the path below.

const crypto = require('crypto');

const signingKey = $env.CALENDLY_WEBHOOK_SIGNING_KEY;
const sigHeader = $input.item.json.headers['calendly-webhook-signature'];

let signatureValid = false;
let reason = '';

if (!signingKey) {
  reason = 'CALENDLY_WEBHOOK_SIGNING_KEY is not set on this n8n instance';
} else if (!sigHeader) {
  reason = 'Missing Calendly-Webhook-Signature header';
} else {
  try {
    const parts = Object.fromEntries(
      sigHeader.split(',').map((p) => p.split('=').map((s) => s.trim())),
    );
    const rawBodyBuffer = $input.item.binary?.data?.data
      ? Buffer.from($input.item.binary.data.data, 'base64')
      : Buffer.from(JSON.stringify($input.item.json.body));
    const signedPayload = `${parts.t}.${rawBodyBuffer.toString('utf8')}`;
    const expected = crypto
      .createHmac('sha256', signingKey)
      .update(signedPayload)
      .digest('hex');
    signatureValid = crypto.timingSafeEqual(
      Buffer.from(expected, 'hex'),
      Buffer.from(parts.v1 || '', 'hex'),
    );
    if (!signatureValid) reason = 'Signature mismatch';
  } catch (err) {
    reason = `Verification error: ${err.message}`;
  }
}

return [{ json: { ...$input.item.json.body, signatureValid, signatureFailureReason: reason } }];
